/**
 * MedX field forms runtime — runs on `npm run start` via medx-runtime-registry.cjs
 * Generic form field wrapper and error slots.
 */
const FIELD_TOKENS = Object.freeze({
  primary: { value: "forms-field-primary", scope: "forms" },
  secondary: { value: "forms-field-secondary", scope: "forms" },
  muted: { value: "forms-field-muted", scope: "forms" },
  accent: { value: "forms-field-accent", scope: "forms" },
  surface: { value: "forms-field-surface", scope: "forms" },
});

const FIELD_PRESETS = Object.freeze({
  default: { token: "primary", enabled: true, priority: 1 },
  compact: { token: "secondary", enabled: true, priority: 2 },
  emphasis: { token: "accent", enabled: true, priority: 3 },
  subtle: { token: "muted", enabled: true, priority: 4 },
});

const FIELD_SUPPLY_CHAIN = Object.freeze({
  inventory: { label: "Inventory", key: "inventory", tier: "ops" },
  orders: { label: "Orders", key: "orders", tier: "ops" },
  compliance: { label: "Compliance", key: "compliance", tier: "regulatory" },
  coldChain: { label: "Cold chain", key: "cold-chain", tier: "ops" },
  blockchain: { label: "Blockchain", key: "blockchain", tier: "integrations" },
});

const fieldRegistry = new Map();
const FIELD_listeners = new Set();
let FIELD_seq = 0;

function createFieldId(prefix = "medx-forms-field") {
  FIELD_seq += 1;
  return `${prefix}-${FIELD_seq}`;
}

function registerField(config = {}) {
  const entryId = config.id ?? createFieldId();
  const preset = FIELD_PRESETS[config.preset ?? "default"] ?? FIELD_PRESETS.default;
  const token = FIELD_TOKENS[config.token ?? preset.token] ?? FIELD_TOKENS.primary;
  const entry = {
    id: entryId,
    preset: config.preset ?? "default",
    token,
    domain: config.domain ?? "inventory",
    domainMeta: FIELD_SUPPLY_CHAIN[config.domain ?? "inventory"] ?? null,
    enabled: config.enabled ?? preset.enabled,
    priority: config.priority ?? preset.priority,
    metadata: config.metadata ?? {},
    createdAt: Date.now(),
    onChange: typeof config.onChange === "function" ? config.onChange : null,
  };
  fieldRegistry.set(entryId, entry);
  notifyFieldListeners("register", entry);
  return entry;
}

function updateField(id, patch = {}) {
  const entry = fieldRegistry.get(id);
  if (!entry) return null;
  Object.assign(entry, patch, { updatedAt: Date.now() });
  if (entry.onChange) entry.onChange(entry);
  notifyFieldListeners("update", entry);
  return entry;
}

function resolveField(id) {
  const entry = fieldRegistry.get(id);
  if (!entry) return null;
  return {
    id: entry.id,
    token: entry.token.value,
    domain: entry.domain,
    enabled: entry.enabled,
    priority: entry.priority,
    label: entry.domainMeta?.label ?? entry.domain,
  };
}

function listFieldEntries(filter = {}) {
  let items = Array.from(fieldRegistry.values());
  if (filter.domain) items = items.filter((e) => e.domain === filter.domain);
  if (filter.enabled != null) items = items.filter((e) => e.enabled === filter.enabled);
  return items.sort((a, b) => a.priority - b.priority);
}

function onFieldEvent(listener) {
  FIELD_listeners.add(listener);
  return () => FIELD_listeners.delete(listener);
}

function notifyFieldListeners(type, entry) {
  for (const listener of FIELD_listeners) {
    try {
      listener({ type, entry, registrySize: fieldRegistry.size });
    } catch (err) {
      console.warn("[medx:ui:forms:field] listener error", err.message);
    }
  }
}

function getFieldMetrics() {
  const items = listFieldEntries();
  return {
    total: items.length,
    enabled: items.filter((e) => e.enabled).length,
    domains: [...new Set(items.map((e) => e.domain))],
    tokens: Object.keys(FIELD_TOKENS).length,
    presets: Object.keys(FIELD_PRESETS).length,
  };
}

async function runMedxField() {
  console.log("[medx:ui:forms:field] runtime initialized");
  console.log(`[medx:ui:forms:field] tokens=${Object.keys(FIELD_TOKENS).length} presets=${Object.keys(FIELD_PRESETS).length}`);

  const events = [];
  onFieldEvent((e) => events.push(e.type));

  const domains = Object.keys(FIELD_SUPPLY_CHAIN);
  const presets = Object.keys(FIELD_PRESETS);
  for (let i = 0; i < domains.length; i += 1) {
    registerField({
      domain: domains[i],
      preset: presets[i % presets.length],
      metadata: { seed: i, module: "forms/field" },
    });
  }

  const first = listFieldEntries()[0];
  if (first) updateField(first.id, { priority: 0, metadata: { ...first.metadata, promoted: true } });

  const metrics = getFieldMetrics();
  const resolved = first ? resolveField(first.id) : null;

  console.log(`[medx:ui:forms:field] registered=${metrics.total} enabled=${metrics.enabled}`);
  console.log(`[medx:ui:forms:field] domains=${metrics.domains.join(",")}`);
  console.log(`[medx:ui:forms:field] events=${events.join(",")}`);
  if (resolved) console.log(`[medx:ui:forms:field] sample=${resolved.token}:${resolved.domain}`);
  console.log("[medx:ui:forms:field] bootstrap complete");
}

module.exports = runMedxField;
